class Solution {
    public int minChanges(int[] nums, int k) {
        int n = nums.length;
        int res = n;
        for (int i = 0; i < n; i++) {
            int cnt = 0;
            int xor = 0;
            for (int j = i; j < n; j++) {
                xor ^= nums[j];
                if ((j - i + 1) % k == 0) {
                    if (xor == 0) cnt++;
                    else cnt = 0;
                    res = Math.min(res, n - cnt * k);
                }
            }
        }
        return res;
    }
}
